import{_ as s,o as n,c as t,a2 as e}from"./chunks/framework.DS_HIvHc.js";const u=JSON.parse('{"title":"MCP 연동 가이드","description":"","frontmatter":{},"headers":[],"relativePath":"guide/mcp.md","filePath":"guide/mcp.md","lastUpdated":1773714265000}'),p={name:"guide/mcp.md"};function l(o,a,i,d,c,r){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="mcp-연동-가이드" tabindex="-1">MCP 연동 가이드 <a class="header-anchor" href="#mcp-연동-가이드" aria-label="Permalink to &quot;MCP 연동 가이드&quot;">​</a></h1><blockquote><p>Claude에게 새로운 능력을 추가하는 플러그인, MCP. 회사에서 쓰는 도구들과 Claude를 연결하면 업무가 훨씬 편해집니다.</p></blockquote><h2 id="mcp가-뭔가요" tabindex="-1">MCP가 뭔가요? <a class="header-anchor" href="#mcp가-뭔가요" aria-label="Permalink to &quot;MCP가 뭔가요?&quot;">​</a></h2><p>**MCP(Model Context Protocol)**는 Claude가 외부 서비스와 대화할 수 있게 해주는 <strong>플러그인 시스템</strong>입니다.</p><p>비유하자면 이렇습니다:</p><ul><li>Claude 자체 = 똑똑한 비서</li><li>MCP = 비서에게 주는 <strong>열쇠 묶음</strong></li></ul><p>열쇠가 없으면 비서가 아무리 똑똑해도 구글 드라이브 파일을 열어볼 수 없고, 슬랙 메시지를 검색할 수 없고, 캘린더를 확인할 수 없습니다. MCP는 이 열쇠를 Claude에게 건네주는 방법입니다.</p><div class="info custom-block"><p class="custom-block-title">핵심 개념</p><p>MCP를 설치하면 Claude가 <strong>직접</strong> 회사 도구에 접근합니다. &quot;복사해서 붙여넣기&quot; 할 필요 없이, &quot;슬랙에서 찾아줘&quot;라고 말하면 됩니다.</p></div><h2 id="mcp로-할-수-있는-것들" tabindex="-1">MCP로 할 수 있는 것들 <a class="header-anchor" href="#mcp로-할-수-있는-것들" aria-label="Permalink to &quot;MCP로 할 수 있는 것들&quot;">​</a></h2><table tabindex="0"><thead><tr><th>연동 서비스</th><th>할 수 있는 것</th><th>활용 예시</th></tr></thead><tbody><tr><td><strong>Google Drive</strong></td><td>파일 검색, 문서 읽기, 내용 요약</td><td>&quot;지난달 마케팅 보고서 찾아서 요약해줘&quot;</td></tr><tr><td><strong>Slack</strong></td><td>메시지 검색, 채널 요약, 스레드 정리</td><td>&quot;이번 주 #개발팀 채널 논의 정리해줘&quot;</td></tr><tr><td><strong>GitHub</strong></td><td>이슈 조회, PR 확인, 코드 리뷰 요약</td><td>&quot;이번 스프린트 열린 이슈 목록 보여줘&quot;</td></tr><tr><td><strong>Google Calendar</strong></td><td>일정 확인, 빈 시간 찾기, 미팅 잡기</td><td>&quot;다음 주 화~목 중 팀 미팅 가능한 시간 찾아줘&quot;</td></tr><tr><td><strong>사내 DB</strong></td><td>데이터 조회, 리포트 생성</td><td>&quot;이번 달 신규 고객 수 알려줘&quot;</td></tr><tr><td><strong>Notion</strong></td><td>페이지 검색, 위키 조회</td><td>&quot;온보딩 가이드 찾아서 핵심만 알려줘&quot;</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">꿀팁</p><p>MCP는 계속 늘어나고 있습니다. 필요한 연동이 있다면 IT팀에 문의해보세요. 대부분의 업무 도구는 MCP로 연결할 수 있습니다.</p></div><h2 id="mcp-설치-방법" tabindex="-1">MCP 설치 방법 <a class="header-anchor" href="#mcp-설치-방법" aria-label="Permalink to &quot;MCP 설치 방법&quot;">​</a></h2><h3 id="_1단계-claude-desktop-설정-열기" tabindex="-1">1단계: Claude Desktop 설정 열기 <a class="header-anchor" href="#_1단계-claude-desktop-설정-열기" aria-label="Permalink to &quot;1단계: Claude Desktop 설정 열기&quot;">​</a></h3><p>Claude Desktop 좌측 하단의 <strong>설정(⚙️)</strong> 아이콘을 클릭합니다.</p><h3 id="_2단계-mcp-서버-추가" tabindex="-1">2단계: MCP 서버 추가 <a class="header-anchor" href="#_2단계-mcp-서버-추가" aria-label="Permalink to &quot;2단계: MCP 서버 추가&quot;">​</a></h3><p>설정 화면에서 <strong>&quot;MCP Servers&quot;</strong> 탭을 선택하고, <strong>&quot;Add Server&quot;</strong> 버튼을 클릭합니다.</p><h3 id="_3단계-연동할-서비스-선택" tabindex="-1">3단계: 연동할 서비스 선택 <a class="header-anchor" href="#_3단계-연동할-서비스-선택" aria-label="Permalink to &quot;3단계: 연동할 서비스 선택&quot;">​</a></h3><p>연결하고 싶은 서비스를 목록에서 선택합니다. 예를 들어, Google Drive를 연동하려면:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. &quot;Add Server&quot; 클릭</span></span>
<span class="line"><span>2. &quot;Google Drive&quot; 선택</span></span>
<span class="line"><span>3. Google 계정 로그인 (회사 계정 사용)</span></span>
<span class="line"><span>4. 접근 권한 허용</span></span>
<span class="line"><span>5. 연결 완료!</span></span></code></pre></div><h3 id="_4단계-연결-확인" tabindex="-1">4단계: 연결 확인 <a class="header-anchor" href="#_4단계-연결-확인" aria-label="Permalink to &quot;4단계: 연결 확인&quot;">​</a></h3><p>대화창에서 아래처럼 물어보면 잘 연결됐는지 확인할 수 있습니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>지금 연결된 MCP 서비스 목록 보여줘.</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">IT팀 확인 필요</p><p>회사에서 MCP를 사용하려면 IT팀의 승인이 필요할 수 있습니다. 먼저 IT팀에 &quot;Claude Desktop MCP 사용 가능 여부&quot;를 확인하세요. 회사 보안 정책에 따라 사용 가능한 MCP가 제한될 수 있습니다.</p></div><h2 id="실전-활용-시나리오" tabindex="-1">실전 활용 시나리오 <a class="header-anchor" href="#실전-활용-시나리오" aria-label="Permalink to &quot;실전 활용 시나리오&quot;">​</a></h2><h3 id="시나리오-1-슬랙-논의-요약" tabindex="-1">시나리오 1: 슬랙 논의 요약 <a class="header-anchor" href="#시나리오-1-슬랙-논의-요약" aria-label="Permalink to &quot;시나리오 1: 슬랙 논의 요약&quot;">​</a></h3><p><strong>상황:</strong> 출장 다녀왔더니 슬랙 메시지가 500개 쌓여 있을 때</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>슬랙에서 이번 주 #마케팅팀 채널 논의 요약해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>알고 싶은 것:</span></span>
<span class="line"><span>- 주요 결정 사항</span></span>
<span class="line"><span>- 나한테 관련된 멘션이 있었는지</span></span>
<span class="line"><span>- 다음 주까지 해야 할 액션 아이템</span></span></code></pre></div><h3 id="시나리오-2-구글-드라이브-파일-찾기" tabindex="-1">시나리오 2: 구글 드라이브 파일 찾기 <a class="header-anchor" href="#시나리오-2-구글-드라이브-파일-찾기" aria-label="Permalink to &quot;시나리오 2: 구글 드라이브 파일 찾기&quot;">​</a></h3><p><strong>상황:</strong> 파일 이름이 정확히 기억 안 나는데 지난달 보고서를 찾아야 할 때</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>구글 드라이브에서 지난달(2월)에 만든 보고서 파일 찾아줘.</span></span>
<span class="line"><span>&quot;매출&quot; 또는 &quot;실적&quot;이라는 단어가 들어간 문서로.</span></span>
<span class="line"><span>찾으면 핵심 내용 3줄로 요약해줘.</span></span></code></pre></div><h3 id="시나리오-3-캘린더에서-빈-시간-찾기" tabindex="-1">시나리오 3: 캘린더에서 빈 시간 찾기 <a class="header-anchor" href="#시나리오-3-캘린더에서-빈-시간-찾기" aria-label="Permalink to &quot;시나리오 3: 캘린더에서 빈 시간 찾기&quot;">​</a></h3><p><strong>상황:</strong> 팀원 5명의 일정을 맞춰 미팅을 잡아야 할 때</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>내 캘린더에서 다음 주 빈 시간 찾아줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>조건:</span></span>
<span class="line"><span>- 월~금, 오전 10시~오후 5시 사이</span></span>
<span class="line"><span>- 최소 1시간 블록</span></span>
<span class="line"><span>- 점심시간(12~1시) 제외</span></span>
<span class="line"><span>가능한 시간대를 목록으로 보여줘.</span></span></code></pre></div><h3 id="시나리오-4-github-이슈-관리" tabindex="-1">시나리오 4: GitHub 이슈 관리 <a class="header-anchor" href="#시나리오-4-github-이슈-관리" aria-label="Permalink to &quot;시나리오 4: GitHub 이슈 관리&quot;">​</a></h3><p><strong>상황:</strong> 스프린트 회의 전에 이슈 현황을 빠르게 파악해야 할 때</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub에서 우리 프로젝트 이슈 현황 정리해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>보고 싶은 것:</span></span>
<span class="line"><span>- 이번 스프린트 열린 이슈 수</span></span>
<span class="line"><span>- 우선순위별 분류 (긴급/보통/낮음)</span></span>
<span class="line"><span>- 담당자별 할당 현황</span></span>
<span class="line"><span>표로 정리해줘.</span></span></code></pre></div><h2 id="주의사항" tabindex="-1">주의사항 <a class="header-anchor" href="#주의사항" aria-label="Permalink to &quot;주의사항&quot;">​</a></h2><h3 id="권한-관리" tabindex="-1">권한 관리 <a class="header-anchor" href="#권한-관리" aria-label="Permalink to &quot;권한 관리&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>확인 사항</th></tr></thead><tbody><tr><td><strong>최소 권한 원칙</strong></td><td>필요한 권한만 허용하세요. &quot;모든 파일 접근&quot;보다 &quot;특정 폴더만 접근&quot;이 안전합니다</td></tr><tr><td><strong>회사 계정 사용</strong></td><td>MCP 연동 시 반드시 회사 계정으로 로그인하세요. 개인 계정 사용은 보안 이슈가 됩니다</td></tr><tr><td><strong>정기 점검</strong></td><td>더 이상 안 쓰는 MCP 연동은 해제하세요. 설정에서 연결된 서비스 목록을 주기적으로 확인합니다</td></tr></tbody></table><h3 id="보안-고려사항" tabindex="-1">보안 고려사항 <a class="header-anchor" href="#보안-고려사항" aria-label="Permalink to &quot;보안 고려사항&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">민감 정보 주의</p><ul><li><strong>기밀 문서</strong>: MCP로 접근하는 문서에 기밀 정보가 포함되어 있을 수 있습니다. Claude에게 요약을 요청한 결과를 외부에 공유하지 마세요.</li><li><strong>개인정보</strong>: 고객 개인정보가 포함된 DB를 조회할 때는 회사 개인정보처리방침을 확인하세요.</li><li><strong>접근 로그</strong>: MCP를 통한 접근도 서비스에 로그가 남을 수 있습니다. 업무 목적으로만 사용하세요.</li></ul></div><h2 id="it팀에-요청하기" tabindex="-1">IT팀에 요청하기 <a class="header-anchor" href="#it팀에-요청하기" aria-label="Permalink to &quot;IT팀에 요청하기&quot;">​</a></h2><p>MCP 도입을 검토 중이라면, 아래 체크리스트를 IT팀과 함께 확인하세요.</p><h3 id="mcp-도입-협의-체크리스트" tabindex="-1">MCP 도입 협의 체크리스트 <a class="header-anchor" href="#mcp-도입-협의-체크리스트" aria-label="Permalink to &quot;MCP 도입 협의 체크리스트&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ 사용 가능한 MCP 서버 목록 확인</span></span>
<span class="line"><span>□ 회사 보안 정책과의 호환성 검토</span></span>
<span class="line"><span>□ 직원별 접근 권한 범위 설정</span></span>
<span class="line"><span>□ 데이터가 외부로 전송되는 경로 확인</span></span>
<span class="line"><span>□ 개인정보 처리 관련 법적 검토 (PIPA 등)</span></span>
<span class="line"><span>□ MCP 연동 시 사용할 계정 정책 (개인/공용)</span></span>
<span class="line"><span>□ 문제 발생 시 지원 체계 (담당자, 연락처)</span></span>
<span class="line"><span>□ 도입 후 모니터링 및 감사 계획</span></span>
<span class="line"><span>□ 직원 교육 및 가이드 배포 일정</span></span>
<span class="line"><span>□ 시범 운영 범위 및 기간 결정</span></span></code></pre></div><h3 id="it팀-요청-메일-예시" tabindex="-1">IT팀 요청 메일 예시 <a class="header-anchor" href="#it팀-요청-메일-예시" aria-label="Permalink to &quot;IT팀 요청 메일 예시&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>제목: Claude Desktop MCP 연동 검토 요청</span></span>
<span class="line"><span></span></span>
<span class="line"><span>안녕하세요, [부서명] [이름]입니다.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>업무 효율화를 위해 Claude Desktop의 MCP(Model Context Protocol) 기능</span></span>
<span class="line"><span>도입을 검토하고 있습니다.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>연동 희망 서비스: Google Drive, Slack</span></span>
<span class="line"><span>예상 사용 인원: [N]명</span></span>
<span class="line"><span>주요 활용 목적: 문서 검색 및 요약, 채널 논의 정리</span></span>
<span class="line"><span></span></span>
<span class="line"><span>보안 정책 검토 및 테스트 계정 발급이 가능한지 확인 부탁드립니다.</span></span>
<span class="line"><span>감사합니다.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">도입 전략</p><p>한 번에 모든 서비스를 연동하기보다, <strong>가장 많이 쓰는 서비스 1~2개</strong>부터 시범 운영하는 것을 추천합니다. 효과를 확인한 후 점차 확대하면 IT팀 설득도 쉬워집니다.</p></div>`,48)])])}const g=s(p,[["render",l]]);export{u as __pageData,g as default};
